// ============================================================
// FORMAT OUTPUT — NO SANITIZATION (Intentional Vulnerability)
// ============================================================
// This node takes the raw LLM response and extracts Summary +
// Category. It performs ZERO sanitization on the output.
// If the LLM included <script> tags, <img onerror=...>, or
// any other HTML/JS, it passes straight through to the CSV.
// ============================================================

const llmResponse = $input.first().json.text || $input.first().json.response || '';
const originalName = $('Receive Feedback').first().json.body.name || 'Anonymous';

let summary = llmResponse;
let category = 'General';

// Parse the LLM's structured response
const summaryMatch = llmResponse.match(/Summary:\s*(.*?)(?=\nCategory:|$)/si);
const categoryMatch = llmResponse.match(/Category:\s*(.*?)$/mi);

if (summaryMatch) summary = summaryMatch[1].trim();
if (categoryMatch) category = categoryMatch[1].trim();

// ⚠️  NO escaping, NO stripping of HTML tags, NO encoding.
//     This is the core of the LLM05 vulnerability.
return [{
  json: {
    name: originalName,
    summary: summary,
    category: category,
    timestamp: new Date().toISOString()
  }
}];
